"use client";

import { useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import Navbar from "@/components/Navbar";
import { TrendingUp, Bitcoin, ArrowRight } from "lucide-react";

export default function InvestingPage() {
  const { user, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (!loading && !user) router.push("/login");
  }, [user, loading]);

  if (loading || !user) return null;

  return (
    <div className="pb-24 pt-8 px-6 min-h-screen bg-white dark:bg-black">
      <h1 className="text-3xl font-bold mb-8">Investing</h1>

      <div className="grid grid-cols-2 gap-4">
        <button
          onClick={() => router.push("/stocks")}
          className="flex flex-col justify-between p-6 bg-blue-500 rounded-3xl text-white hover:scale-[1.02] active:scale-95 transition-all shadow-lg shadow-blue-500/20 aspect-square text-left relative overflow-hidden group"
        >
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
            <TrendingUp className="w-24 h-24" strokeWidth={1} />
          </div>
          <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm z-10">
            <TrendingUp className="w-6 h-6" />
          </div>
          <div className="z-10 mt-auto">
            <p className="font-bold text-xl mb-1">Stocks</p>
            <p className="text-sm opacity-90 font-medium">Top 50 US</p>
          </div>
        </button>

        <button
          onClick={() => router.push("/bitcoin")}
          className="flex flex-col justify-between p-6 bg-[#F7931A] rounded-3xl text-white hover:scale-[1.02] active:scale-95 transition-all shadow-lg shadow-[#F7931A]/20 aspect-square text-left relative overflow-hidden group"
        >
          <div className="absolute top-0 right-[-10px] p-4 opacity-10 group-hover:scale-110 transition-transform">
            <Bitcoin className="w-24 h-24" strokeWidth={1} />
          </div>
          <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm z-10">
            <span className="text-2xl font-bold font-serif leading-none mt-1">
              ₿
            </span>
          </div>
          <div className="z-10 mt-auto">
            <p className="font-bold text-xl mb-1">Crypto</p>
            <p className="text-sm opacity-90 font-medium">Bitcoin</p>
          </div>
        </button>
      </div>

      {/* Quick Promo */}
      <div
        className="mt-8 p-6 bg-gray-50 dark:bg-zinc-900 rounded-3xl flex items-center justify-between border border-transparent hover:border-cashapp transition-colors cursor-pointer group"
        onClick={() => router.push("/stocks")}
      >
        <div>
          <p className="font-bold text-lg mb-1">Start Investing</p>
          <p className="text-sm text-gray-500">
            Buy fractions of a stock or crypto for as little as $1.
          </p>
        </div>
        <div className="w-10 h-10 bg-cashapp/10 rounded-full flex items-center justify-center shrink-0 ml-4 group-hover:bg-cashapp group-hover:text-white text-cashapp transition-colors">
          <ArrowRight className="w-5 h-5" />
        </div>
      </div>

      <Navbar />
    </div>
  );
}
